+    #[test]
+    fn test_prepared_direct_simple_insert_normal_autocommit_clears_append_hint() {
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("normal_autocommit_append_hint.db");
+        let db_path = db_path.to_string_lossy().into_owned();
+        let conn = Connection::open(db_path).unwrap();
+        conn.autocommit_retain_enabled.set(false);
+        conn.execute(
+            "CREATE TABLE prep_direct_file_autohint (id INTEGER PRIMARY KEY, name TEXT NOT NULL);",
+        )
+        .unwrap();
+        let stmt = conn
+            .prepare("INSERT INTO prep_direct_file_autohint VALUES (NULL, ?1)")
+            .unwrap();
+
+        assert_eq!(
+            conn.execute_prepared_with_params(&stmt, &[SqliteValue::Text("file-backed".into())])
+                .unwrap(),
+            1
+        );
+        assert!(
+            conn.prepared_direct_insert_append_hint.borrow().is_none(),
+            "normal autocommit commit must not leave an append hint whose retained leaf image belongs to the closed implicit transaction"
+        );
+
+        let rows = conn
+            .query("SELECT id, name FROM prep_direct_file_autohint ORDER BY id")
+            .unwrap();
+        assert_eq!(rows.len(), 1);
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(1));
+        assert_eq!(
+            rows[0].values()[1],
+            SqliteValue::Text("file-backed".into())
+        );
+    }
